sp_page.css:
section.flex-grow.page.sp-scroll.flex-column{
	//background-color: #F9FAFB; //background color of page
}

.table-striped > tbody > tr:nth-of-type(odd){
	background-color: #fff !important; //odd colors of strip
}

.panel{
	border-radius: 1rem;
}

.panel-tile {
	margin: 2rem 0 .6rem 2rem; //all statement heading
}

  .pagination-wrapper {
    width: 100%;
    display: flex;
    justify-content: center;  /* THIS centers it */
  }

  .svg:not(:root) {
    overflow: visible;
    background: white;
	}
.btn-xs{
	background: white;
  line-height: 0 !important;
}

.view {
    color: transparent !important;
  }
.pg-info {
    font-size: 1.3rem;
    color: #6b7280;
    padding: 6px 14px;
  }


.pagination-container {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: .1rem;
  margin-top: 15px;
}

/* Base button */
.pg-btn {
  padding: 6px 16px;
  border-radius: 0.5rem;
  border: 1px solid #dcdcdc;
  background: #f9f9f9;
  color: #333;
  font-size: 13px;
  transition: all 0.2s ease;
}

/* Hover effect (only when enabled) */
.pg-btn:hover:not(:disabled) {
  background: #f0f4ff;
  border-color: #bcd3ff;
  color: black;
}

/* Disabled (Prev in your screenshot) */
.pg-btn:disabled {
  background: #f3f3f3;
  color: #b5b5b5;
  border-color: #e5e5e5;
  cursor: not-allowed;
  opacity: 0.5;
}

/* Active button (Next in your screenshot) */
.pg-btn.active {
  background: #ffffff;
  border: 1px solid #cfd8e3;
  color: color;
  font-weight: 500;
  box-shadow: 0 1px 2px rgba(0,0,0,0.05);
}
